199→/// Execute a function with pre-generated inputs and collect execution traces.
200→///
201→/// Handles the full observation lifecycle: instrument → setup → execute batch →
202→/// teardown. Returns `ObservationOutput` compatible with the rest of the pipeline.
203→///
204→/// Callers supply pre-generated inputs (random, boundary, user-provided). This
205→/// function does not generate inputs — that separation keeps the observe stage
206→/// composable and testable.
207→pub async fn observe_function(
208→    frontend: &mut Frontend,
209→    analysis: &FunctionAnalysis,
210→    inputs: Vec<Vec<serde_json::Value>>,
211→    config: &ObserveConfig,
212→) -> Result<ObservationOutput, ObserveError> {
213→    let total_input_count = inputs.len() as u32;
214→
215→    // --- Instrumentation ---
216→    let instrumentable_line_count = if config.skip_instrument {
217→        None
218→    } else {
219→        let instrument_response = frontend
220→            .send(ProtoCommand::Instrument {
221→                file: config.file.clone(),
222→                function: analysis.name.clone(),
223→                mocks: config.mocks.clone(),
224→                project_root: config.project_root.clone(),
225→            })
226→            .await?;
227→
228→        match instrument_response.result {
229→            ResponseResult::Instrument {
230→                instrumented,
231→                instrumentable_line_count,
232→                ..
233→            } => {
234→                if !instrumented {
235→                    return Err(ObserveError::InstrumentationFailed(
236→                        "instrumentation returned instrumented=false".to_string(),
237→                    ));
238→                }
239→                instrumentable_line_count
240→            }
241→            ResponseResult::Error { code, message, .. } => {
242→                return Err(ObserveError::InstrumentationFailed(format!(
243→                    "instrument error ({code:?}): {message}"
244→                )));
245→            }
246→            other => {
247→                return Err(ObserveError::UnexpectedResponse(format!(
248→                    "expected Instrument response, got {other:?}"
249→                )));
250→            }
251→        }
252→    };
253→
254→    // --- Setup lifecycle ---
255→    let has_setup =
256→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
257→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
258→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
259→
260→    let mut setup_context: Option<SetupContextStack> = None;
261→
262→    if per_function_setup
263→        && let Some(ref setup_file) = config.setup_file
264→    {
265→        setup_context = send_setup(
266→            frontend,
267→            setup_file,
268→            &analysis.name,
269→            config.setup_level,
270→            config.project_root.clone(),
271→        )
272→        .await?;
273→    }
274→
275→    // --- Execute batch ---
276→    // For per-execution setup, we need to interleave setup/teardown with each execution.
277→    let batch = if per_execution_setup {
278→        observe_batch_with_per_execution_setup(
279→            frontend,
280→            analysis,
281→            inputs,
282→            config,
283→        )
284→        .await?
285→    } else {
286→        observe_batch(
287→            frontend,
288→            &analysis.name,
289→            inputs,
290→            &config.mocks,
291→            setup_context.as_ref(),
292→            &config.loop_buckets,
293→            config.timeout,
294→        )
295→        .await?
296→    };
297→
298→    // --- Per-function teardown ---
299→    if per_function_setup && frontend_supports(&config.capabilities, "teardown") {
300→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
301→    }
302→
303→    let total_lines = instrumentable_line_count
304→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
305→
306→    Ok(ObservationOutput {
307→        function_name: analysis.name.clone(),
308→        iterations: total_input_count,
309→        unique_paths: batch.unique_path_hashes.len(),
310→        lines_covered: batch.lines_covered.len(),
311→        total_lines,
312→        new_path_executions: batch.new_path_executions,
313→        raw_results: batch.raw_results,
314→        discoveries: batch.discoveries,
315→        nondeterministic_fields: vec![],
316→        float_probe_results: vec![],
317→    })
318→}
319→
320→/// Execute inputs with per-execution setup/teardown interleaved.
321→async fn observe_batch_with_per_execution_setup(
322→    frontend: &mut Frontend,
323→    analysis: &FunctionAnalysis,
324→    inputs: Vec<Vec<serde_json::Value>>,
325→    config: &ObserveConfig,
326→) -> Result<BatchObservation, ObserveError> {
327→    let mut seen_paths: HashSet<u64> = HashSet::new();
328→    let mut all_lines: HashSet<u32> = HashSet::new();
329→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
330→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
331→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
332→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
333→
334→    let start = Instant::now();
335→
336→    for input in inputs {
337→        if config.timeout.is_some_and(|t| start.elapsed() >= t) {
338→            break;
339→        }
340→
341→        // Per-execution setup
342→        let setup_context = if let Some(ref setup_file) = config.setup_file {
343→            send_setup(
344→                frontend,
345→                setup_file,
346→                &analysis.name,
347→                config.setup_level,
348→                config.project_root.clone(),
349→            )
350→            .await?
351→        } else {
352→            None
353→        };
354→
355→        let response = frontend
356→            .send(ProtoCommand::Execute {
357→                function: analysis.name.clone(),
358→                inputs: input.clone(),
359→                mocks: config.mocks.clone(),
360→                setup_context,
361→            })
362→            .await?;
363→
364→        let exec_result = match response.result {
365→            ResponseResult::Execute(result) => *result,
366→            ResponseResult::Error { code, message, .. } => {
367→                return Err(ObserveError::UnexpectedResponse(format!(
368→                    "execute error ({code:?}): {message}"
369→                )));
370→            }
371→            other => {
372→                return Err(ObserveError::UnexpectedResponse(format!(
373→                    "expected Execute response, got {other:?}"
374→                )));
375→            }
376→        };
377→
378→        // Per-execution teardown
379→        if frontend_supports(&config.capabilities, "teardown") {
380→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
381→        }
382→
383→        for &line in &exec_result.lines_executed {
384→            all_lines.insert(line);
385→        }
386→
387→        let hash = path_hash(&exec_result, &config.loop_buckets);
388→        let is_new = seen_paths.insert(hash);
389→
390→        for decision in &exec_result.branch_path {
391→            if seen_branch_ids.insert(decision.branch_id) {
392→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
393→            }
394→        }
395→
396→        if is_new {
397→            let error_intent = classify_error_intent(&exec_result);
398→            new_path_executions.push(ExecutionSummary {
399→                inputs: input.clone(),
400→                return_value: exec_result.return_value.clone(),
401→                thrown_error: exec_result
402→                    .thrown_error
403→                    .as_ref()
404→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
405→                lines_executed: exec_result.lines_executed.clone(),
406→                is_new_path: true,
407→                error_intent,
408→            });
409→        }
410→
411→        raw_results.push((input, config.mocks.clone(), exec_result));
412→    }
413→
414→    Ok(BatchObservation {
415→        raw_results,
416→        unique_path_hashes: seen_paths,
417→        lines_covered: all_lines,
418→        discoveries,
419→        new_path_executions,
420→    })
421→}
