1066→/// Simple input fuzzing: produce a handful of variations on the base inputs.
1067→///
1068→/// For each JSON value in the input list, generate mutations:
1069→/// - Numbers: ±1, ×-1, 0, boundary values
1070→/// - Booleans: flip
1071→/// - Strings: empty string, "a"
1072→pub(crate) fn fuzz_inputs(base: &[serde_json::Value]) -> Vec<Vec<serde_json::Value>> {
1073→    let mut results = Vec::new();
1074→
1075→    for (idx, val) in base.iter().enumerate() {
1076→        let mutations = fuzz_single_value(val);
1077→        for mutated in mutations {
1078→            let mut new_inputs = base.to_vec();
1079→            new_inputs[idx] = mutated;
1080→            results.push(new_inputs);
1081→        }
1082→    }
1083→
1084→    results
1085→}
1086→
1087→pub(crate) fn fuzz_single_value(val: &serde_json::Value) -> Vec<serde_json::Value> {
1088→    match val {
1089→        serde_json::Value::Number(n) => {
1090→            let mut mutations = Vec::new();
1091→            if let Some(i) = n.as_i64() {
1092→                let candidates = [i + 1, i - 1, 0, -i];
1093→                for c in candidates {
1094→                    let json_val = serde_json::json!(c);
1095→                    if c != i && !mutations.contains(&json_val) {
1096→                        mutations.push(json_val);
1097→                    }
1098→                }
1099→            } else if let Some(f) = n.as_f64() {
1100→                let candidates = [f + 1.0, f - 1.0, 0.0];
1101→                for c in candidates {
1102→                    let json_val = serde_json::json!(c);
1103→                    if (c - f).abs() > f64::EPSILON && !mutations.contains(&json_val) {
1104→                        mutations.push(json_val);
1105→                    }
1106→                }
1107→            }
1108→            mutations
1109→        }
1110→        serde_json::Value::Bool(b) => vec![serde_json::json!(!b)],
1111→        serde_json::Value::String(_) => {
1112→            vec![serde_json::json!(""), serde_json::json!("a")]
1113→        }
1114→        _ => vec![],
1115→    }
1116→}
